parameters.jsCode:
// Filtert auf ALLE Zeilen, die auf eine Headline/Subline-Auswahl per Matrix
// warten (koennen mehrere gleichzeitig sein - die Vorgangsnummer ist seit
// V2 Teil des Codes, deshalb keine Mehrdeutigkeit mehr bei parallelen Wartern),
// und liest je Zeile die Kandidaten sowie den Zeitstempel des Matrix-Posts aus
// visualJson.headlineCandidates / visualJson.candidatesPostedAt.
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try {
    const p = JSON.parse(String(v));
    return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {};
  } catch (e) {
    return {};
  }
}

const waiting = items.filter(item => String(item.json.headlineChoiceStage || '').trim() === 'awaiting_headline_choice');

if (waiting.length === 0) {
  return [];
}

return waiting.map(item => {
  const row = item.json;
  const vj = parseObj(row.visualJson);
  const candidates = Array.isArray(vj.headlineCandidates) ? vj.headlineCandidates : [];
  const candidatesPostedAt = vj.candidatesPostedAt || null;
  const lastReminderAt = vj.lastReminderAt || null;
  const reminderCount = Number(vj.reminderCount || 0);
  return {
    json: {
      ...row,
      _headlineCandidates: candidates,
      _candidatesPostedAt: candidatesPostedAt,
      _lastReminderAt: lastReminderAt,
      _reminderCount: reminderCount
    }
  };
});

// Sucht in den zuletzt gelesenen Matrix-Nachrichten nach einer Antwort, die
// exakt (bis auf optionales '#' und Leerzeichen) einem Kandidaten-Code
// entspricht - der Code enthaelt seit V2 die Vorgangsnummer
// (z.B. "2026-192-K2"), deshalb ist die Zuordnung eindeutig, auch wenn
// mehrere Vorgaenge gleichzeitig auf eine Auswahl warten.
// Die blosse Vorgangsnummer mit "-X"-Suffix (z.B. "2026-192-X", OHNE Kandidat)
// ist kein Auswahl-, sondern ein Reroll-Wunsch fuer den GANZEN Vorgang: statt
// der Kandidaten wird er auf visualPromptStage='needs_prompt' zurueckgesetzt
// (imageHeadline/imageSubline geleert), damit P2 beim naechsten planmaessigen
// Lauf komplett neue Headline/Subline-Varianten erzeugt (siehe ZIEL_STATUS in
// "Filtere Visual-Status"). Welcher der vier Kandidaten dabei angegeben wird,
// spielt keine Rolle - deshalb wird fuer den Reroll nur die Vorgangsnummer
// gematcht, kein einzelner Kandidaten-Code.
// Findet sich keine gültige, neue Antwort, endet der Lauf ohne Änderung -
// der nächste Poll (alle 15 Min) versucht es erneut.
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function normCode(v) { return safeStr(v).toLowerCase().replace(/^#/, '').replace(/\s+/g, ''); }
function vnCodeOf(row) { return safeStr(row.vorgangsnummer).replace(/[^0-9A-Za-z]+/g, '-').replace(/^-+|-+$/g, ''); }

const waitingRows = $('Finde wartenden Vorgang').all().map(i => i.json || {});

// Kandidaten-Ebene (fuer normale Auswahl) und Vorgangs-Ebene (fuer Reroll),
// je mit eigener candidatesPostedAt-Grenze (eine Antwort zaehlt nur, wenn sie
// NACH dem Posten der Kandidaten fuer genau diesen Vorgang kam).
const allCandidates = [];
const allRows = [];
for (const row of waitingRows) {
  const candidates = Array.isArray(row._headlineCandidates) ? row._headlineCandidates : [];
  const postedAtMs = row._candidatesPostedAt ? Date.parse(row._candidatesPostedAt) : 0;
  for (const c of candidates) {
    allCandidates.push({ row, candidate: c, postedAtMs, normCode: normCode(c.code) });
  }
  if (candidates.length > 0) {
    allRows.push({ row, postedAtMs, normVnCode: normCode(vnCodeOf(row)) });
  }
}

const chunk = Array.isArray(items[0].json.chunk) ? items[0].json.chunk : [];

const matches = [];
for (const ev of chunk) {
  if (!ev || ev.type !== 'm.room.message') continue;
  const content = ev.content || {};
  if (content.msgtype !== 'm.text') continue;
  const ts = Number(ev.origin_server_ts || 0);
  let replyNorm = normCode(content.body);
  if (!replyNorm) continue;

  let isRerollRequest = false;
  if (replyNorm.endsWith('-x')) {
    isRerollRequest = true;
    replyNorm = replyNorm.slice(0, -2);
  }

  if (isRerollRequest) {
    for (const entry of allRows) {
      if (entry.postedAtMs && ts <= entry.postedAtMs) continue;
      if (entry.normVnCode === replyNorm) {
        matches.push({ ts, isRerollRequest: true, row: entry.row });
      }
    }
  } else {
    for (const entry of allCandidates) {
      if (entry.postedAtMs && ts <= entry.postedAtMs) continue;
      if (entry.normCode === replyNorm) {
        matches.push({ ts, isRerollRequest: false, row: entry.row, candidate: entry.candidate });
      }
    }
  }
}

if (matches.length === 0) {
  return [];
}

// Älteste gültige Antwort nach dem Posten der jeweiligen Kandidaten gewinnt.
matches.sort((a, b) => a.ts - b.ts);
const chosen = matches[0];

const vorgangKeySafe = safeStr(chosen.row.vorgangKey).replace(/[^a-zA-Z0-9]/g, '');

if (chosen.isRerollRequest) {
  return [{
    json: {
      ...chosen.row,
      imageHeadline: '',
      imageSubline: '',
      headlineChoiceStage: 'needs_kernbotschaft',
      visualPromptStage: '',
      imageStage: safeStr(chosen.row.imageFinalPath) ? 'composed' : 'not_started',
      _matrixAction: 'reroll',
      _confirmMessage: '🔄 Ok, für ' + safeStr(chosen.row.vorgangsnummer) + ' - ' + safeStr(chosen.row.title) + ' finde ich eine komplett neue Kernbotschaft. Das dauert bis zum nächsten planmäßigen Durchlauf. Es wird weiterhin nichts veröffentlicht, bis du eine Formulierung bestätigst.',
      _confirmTxnId: 'hdl_confirm_' + vorgangKeySafe + '_reroll_' + Date.now()
    }
  }];
}

// Cutover 2026-07-18: Kandidaten tragen jetzt das volle Satire-Agent-Varianten-Feld-Set
// (nicht mehr nur imageHeadline/imageSubline aus P5s alter Headline-Generierung). Die gewaehlte
// Variante ueberschreibt die kompletten satire*-Spalten, damit Bild-Agent (P5) mit genau der
// Variante arbeitet, die der Mensch fuers Bild ausgewaehlt hat - unabhaengig davon, welche
// Variante P3 automatisch fuer den Text gewaehlt hatte.
function safeArr(v) { return Array.isArray(v) ? v : []; }

return [{
  json: {
    ...chosen.row,
    imageHeadline: safeStr(chosen.candidate.imageHeadline),
    imageSubline: safeStr(chosen.candidate.imageSubline),
    satireBrief: safeStr(chosen.candidate.satireBrief),
    satireAngle: safeStr(chosen.candidate.satireAngle),
    satirePunchlines: JSON.stringify(safeArr(chosen.candidate.satirePunchlines)),
    satireTarget: safeStr(chosen.candidate.satireTarget),
    satireIntensity: Number(chosen.candidate.satireIntensity) || 0,
    satireDoNotClaim: JSON.stringify(safeArr(chosen.candidate.satireDoNotClaim)),
    satireSafetyNote: safeStr(chosen.candidate.satireSafetyNote),
    headlineChoiceStage: 'headline_selected',
    contentStage: 'needs_content',
    imageStage: safeStr(chosen.row.imageFinalPath) ? 'composed' : 'not_started',
    _matrixAction: 'select',
    _confirmMessage: '✅ Danke! Für ' + safeStr(chosen.row.vorgangsnummer) + ' - ' + safeStr(chosen.row.title) + ' wurde übernommen: "' + safeStr(chosen.candidate.imageHeadline) + '" - "' + safeStr(chosen.candidate.imageSubline) + '". Text und Bild werden jetzt freigegeben und beim nächsten planmäßigen Durchlauf veröffentlicht.',
    _confirmTxnId: 'hdl_confirm_' + vorgangKeySafe + '_select_' + normCode(safeStr(chosen.candidate.code)) + '_' + Date.now()
  }
}];

// Prueft, welche wartenden Vorgaenge laenger als REMINDER_INTERVAL_MS keine
// neue Nachricht bekommen haben, und baut dafuer eine Erinnerung mit den
// bereits bestehenden Kandidaten (keine neue KI-Generierung, kein neuer Text).
// Stoppt nach MAX_REMINDERS, damit ein unbeantworteter Vorgang nicht endlos nervt.
//
// FIX (Architekturpruefung 2026-07-22, Befund F3): bisher wurde ein Vorgang nach
// Erreichen von MAX_REMINDERS stillschweigend uebersprungen - unsichtbar in der
// Status-Uebersicht, ohne jede Markierung. Jetzt wird EINMALIG (nicht bei jedem
// 15-Minuten-Lauf erneut) ein sichtbarer Hinweis in visualJson.workflow
// hinterlegt (reminderExhausted/reminderExhaustedAt) - keine neue DB-Spalte
// noetig, da visualJson bereits existiert und bereits von diesem Workflow
// geschrieben wird. headlineChoiceStage bleibt dabei bewusst unveraendert:
// der Mensch kann jederzeit trotzdem noch per Matrix antworten, es werden nur
// keine weiteren automatischen Erinnerungen mehr verschickt.
const REMINDER_INTERVAL_MS = 12 * 60 * 60 * 1000;
const MAX_REMINDERS = 3;

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }
  catch (e) { return {}; }
}

const now = Date.now();
const due = [];

for (const item of items) {
  const row = item.json;
  const reminderCount = Number(row._reminderCount || 0);

  if (reminderCount >= MAX_REMINDERS) {
    const vj = parseObj(row.visualJson);
    const alreadyMarkedExhausted = !!(vj.workflow && vj.workflow.reminderExhausted === true);
    if (alreadyMarkedExhausted) continue;

    vj.workflow = {
      ...(vj.workflow && typeof vj.workflow === 'object' && !Array.isArray(vj.workflow) ? vj.workflow : {}),
      reminderExhausted: true,
      reminderExhaustedAt: new Date().toISOString()
    };

    due.push({
      json: {
        ...row,
        visualJson: JSON.stringify(vj),
        _reminderExhaustedOnly: true
      }
    });
    continue;
  }

  const lastPromptMs = row._lastReminderAt
    ? Date.parse(row._lastReminderAt)
    : (row._candidatesPostedAt ? Date.parse(row._candidatesPostedAt) : 0);
  if (!lastPromptMs || (now - lastPromptMs) < REMINDER_INTERVAL_MS) continue;

  const candidates = Array.isArray(row._headlineCandidates) ? row._headlineCandidates : [];
  if (candidates.length === 0) continue;

  const nextReminderCount = reminderCount + 1;
  const lines = [
    '⏰ Erinnerung (' + nextReminderCount + '/' + MAX_REMINDERS + ') - noch offen: ' + safeStr(row.vorgangsnummer) + ' - ' + safeStr(row.title),
    ''
  ];
  for (const c of candidates) {
    lines.push(safeStr(c.code) + ': ' + safeStr(c.imageHeadline) + ' - ' + safeStr(c.imageSubline));
  }
  lines.push('');
  const exampleCode = candidates.length > 0 ? safeStr(candidates[0].code) : '';
  const vnCode = safeStr(row.vorgangsnummer).replace(/[^0-9A-Za-z]+/g, '-').replace(/^-+|-+$/g, '');
  lines.push('Antworte mit dem gewuenschten Code (z.B. ' + exampleCode + '), um die Auswahl zu bestaetigen, oder mit \'' + vnCode + '-X\' fuer komplett neue Vorschlaege (Vorgangsnummer + -X, ohne Kandidat).');

  const vorgangKeySafe = safeStr(row.vorgangKey).replace(/[^a-zA-Z0-9]/g, '');
  const txnId = 'hdl_remind_' + vorgangKeySafe + '_r' + nextReminderCount;

  due.push({
    json: {
      ...row,
      matrixReminderMessage: lines.join('\n'),
      matrixReminderTxnId: txnId,
      _nextReminderCount: nextReminderCount,
      _reminderExhaustedOnly: false
    }
  });
}

return due;

// Stellt den Vorgangskontext nach dem Matrix-Versand wieder her (gleiches Muster
// wie "Stelle Kontext nach Matrix wieder her" in P2) - der HTTP-Node ersetzt das
// Item-JSON durch die rohe Matrix-API-Antwort und wuerde sonst vorgangKey,
// reminderCount usw. verlieren, sodass "Speichere Erinnerung" keine Zeile findet.
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; } catch (e) { return {}; }
}

const response = $input.item.json || {};
const base = $('Finde erinnerungsfällige Vorgänge').item.json || {};

const hasError = !!(
  response.error ||
  response.errcode ||
  (response.statusCode && Number(response.statusCode) >= 400)
);
const eventId = response.event_id || response.eventId || '';

const existingVisual = parseObj(base.visualJson);

return {
  json: {
    ...base,
    visualJson: JSON.stringify({
      ...existingVisual,
      lastReminderAt: hasError ? (base._lastReminderAt || existingVisual.candidatesPostedAt || null) : new Date().toISOString(),
      reminderCount: hasError ? Number(base._reminderCount || 0) : base._nextReminderCount
    }),
    matrixReminderSentOk: !hasError && !!eventId,
    matrixReminderError: hasError ? (response.error || response.errcode || 'Matrix-Versand fehlgeschlagen') : ''
  }
};
